import { describe, expect, it } from 'vitest';
import { readFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const tokensRoot = resolve(here, '../../../design-tokens/src');

function readTokens(file: string): string {
  return readFileSync(resolve(tokensRoot, file), 'utf8');
}

const tokensDefault = readTokens('tokens-default.css');
const tokensDark = readTokens('tokens-dark.css');
const tokensDrafting = readTokens('tokens-drafting.css');

const lightChrome = [
  '--color-background',
  '--color-foreground',
  '--color-surface',
  '--color-surface-strong',
  '--color-surface-muted',
  '--color-border',
  '--color-border-strong',
  '--color-muted-foreground',
  '--color-accent',
  '--color-accent-foreground',
  '--color-accent-soft',
  '--color-success',
  '--color-warning',
  '--color-danger',
  '--color-info',
  '--color-ring',
];

const spacing = [
  '--space-0',
  '--space-1',
  '--space-2',
  '--space-3',
  '--space-4',
  '--space-5',
  '--space-6',
  '--space-7',
  '--space-8',
  '--space-10',
  '--space-12',
];

const radius = [
  '--radius-xs',
  '--radius-sm',
  '--radius-md',
  '--radius-lg',
  '--radius-xl',
  '--radius-pill',
];

const typography = [
  '--font-sans',
  '--font-mono',
  '--text-xs',
  '--text-sm',
  '--text-base',
  '--text-md',
  '--text-lg',
  '--text-xl',
  '--text-mono-xs',
  '--text-mono-sm',
];

const elevation = ['--elev-0', '--elev-1', '--elev-2', '--elev-3'];

const motion = [
  '--motion-fast',
  '--motion-base',
  '--motion-slow',
  '--ease-out',
  '--ease-in-out',
  '--ease-snap',
];

const drafting = [
  '--draft-paper',
  '--draft-grid-major',
  '--draft-grid-minor',
  '--draft-construction-blue',
  '--draft-witness',
  '--draft-cut',
  '--draft-projection',
  '--draft-hidden',
  '--draft-selection',
  '--draft-hover',
  '--draft-snap',
];

const categories = [
  '--cat-wall',
  '--cat-floor',
  '--cat-roof',
  '--cat-door',
  '--cat-window',
  '--cat-stair',
  '--cat-railing',
  '--cat-room',
  '--cat-site',
  '--cat-section',
  '--cat-sheet',
];

const lineWeights = [
  '--draft-lw-cut-major',
  '--draft-lw-cut-minor',
  '--draft-lw-projection-major',
  '--draft-lw-projection-minor',
  '--draft-lw-hidden',
  '--draft-lw-witness',
  '--draft-lw-construction',
];

describe('design tokens — §9 (default light)', () => {
  it.each(lightChrome)('declares chrome token %s', (token) => {
    expect(tokensDefault).toContain(`${token}:`);
  });

  it.each(spacing)('declares spacing token %s', (token) => {
    expect(tokensDefault).toContain(`${token}:`);
  });

  it.each(radius)('declares radius token %s', (token) => {
    expect(tokensDefault).toContain(`${token}:`);
  });

  it.each(typography)('declares typography token %s', (token) => {
    expect(tokensDefault).toContain(`${token}:`);
  });

  it.each(elevation)('declares elevation token %s', (token) => {
    expect(tokensDefault).toContain(`${token}:`);
  });

  it.each(motion)('declares motion token %s', (token) => {
    expect(tokensDefault).toContain(`${token}:`);
  });
});

describe('design tokens — §9 (dark overrides)', () => {
  it('targets data-theme="dark" and .dark', () => {
    expect(tokensDark).toContain("[data-theme='dark']");
    expect(tokensDark).toContain('.dark');
  });

  it.each(lightChrome)('overrides chrome token %s in dark', (token) => {
    expect(tokensDark).toContain(`${token}:`);
  });
});

describe('design tokens — §9.2 / §9.3 / §9.10 (drafting)', () => {
  it.each(drafting)('declares drafting token %s', (token) => {
    expect(tokensDrafting).toContain(`${token}:`);
  });

  it.each(categories)('declares category token %s', (token) => {
    expect(tokensDrafting).toContain(`${token}:`);
  });

  it.each(lineWeights)('declares line-weight token %s', (token) => {
    expect(tokensDrafting).toContain(`${token}:`);
  });

  it('also declares dark variants of category tokens', () => {
    const darkBlock = tokensDrafting.split("data-theme='dark'")[1] ?? '';
    for (const token of categories) {
      expect(darkBlock).toContain(`${token}:`);
    }
  });
});

describe('tokens-default — backwards-compat aliases', () => {
  it.each([
    '--background',
    '--foreground',
    '--surface',
    '--border',
    '--accent',
    '--accent-foreground',
    '--ring',
    '--muted-foreground',
  ])('keeps legacy alias %s', (token) => {
    expect(tokensDefault).toContain(`${token}:`);
  });
});

export type ElemKind =
  | 'project_settings'
  | 'room_color_scheme'
  | 'wall_type'
  | 'floor_type'
  | 'roof_type'
  | 'level'
  | 'wall'
  | 'door'
  | 'window'
  | 'room'
  | 'grid_line'
  | 'dimension'
  | 'viewpoint'
  | 'issue'
  | 'floor'
  | 'roof'
  | 'stair'
  | 'slab_opening'
  | 'railing'
  | 'family_type'
  | 'room_separation'
  | 'plan_region'
  | 'tag_definition'
  | 'join_geometry'
  | 'section_cut'
  | 'plan_tag_style'
  | 'plan_view'
  | 'view_template'
  | 'sheet'
  | 'schedule'
  | 'site'
  | 'callout'
  | 'bcf'
  | 'agent_assumption'
  | 'agent_deviation'
  | 'validation_rule'
  | 'column'
  | 'beam'
  | 'ceiling';

export type XY = { xMm: number; yMm: number };

export type SiteContextType = 'tree' | 'shrub' | 'neighbor_proxy' | 'entourage';

export type SiteContextObjectRow = {
  id: string;
  contextType: SiteContextType;
  label?: string;
  positionMm: XY;
  scale?: number;
  category?: string;
};

/** Floor-plan graphic detail preset (view template + optional plan_view override). */
export type PlanDetailLevelPlan = 'coarse' | 'medium' | 'fine';

export type PlanCategoryGraphicCategoryKey =
  | 'wall'
  | 'floor'
  | 'roof'
  | 'room'
  | 'door'
  | 'window'
  | 'stair'
  | 'grid_line'
  | 'room_separation'
  | 'dimension';

export type PlanLinePatternToken = 'solid' | 'dash_short' | 'dash_long' | 'dot';

export type PlanCategoryGraphicRow = {
  categoryKey: PlanCategoryGraphicCategoryKey;
  lineWeightFactor?: number | null;
  linePatternToken?: PlanLinePatternToken | null;
};

export type PlanTagTarget = 'opening' | 'room';

export type PlanTagBadgeStyle = 'none' | 'rounded' | 'flag';

